save the below code as .awk file  
example:

cat > logic.awk  
BEGIN {
    RS = "^$";  #.. Reads the whole file as a single line.
    #.. Pattern to match the beginning of a SID_DESC block.
    reSidDesc = "[ ]*[(][^(]*SID_DESC *= *";
    #.. Pattern to match the SID_NAME of the deleted block.
    reSidName = "[(][^(]*SID_NAME *= *" DbName "[^A-Za-z0-9_.]";
}
function Fix (tx, fnData, Local, j, k, Body, Head, nOpen) {

    #.. Split each block, using the Sid Desc as the delimiter.
    split (tx, Body, reSidDesc, Head);
    #.. Search for the block containing the required Sid Name.
    for (j = 1; j in Body; ++j) {
        if (match (Body[j], reSidName)) {
            Head[j-1] = "";     #.. Discard the start of the block.
            #.. Count the level of opening brackets inside the block.
            nOpen = 1 + gsub ("[(]", "(", Body[j]);
            #.. Discard the matching closing brackets.
            for (k = 1; k <= nOpen; ++k)
                sub ("[^)]*[)]", "", Body[j]);
            sub (/^\n/, "", Body[j]);
        }
    }
    #.. Write out what is left.
    printf ("%s", Body[1]) > fnData;
    for (j = 2; j in Body; ++j) {
        printf ("%s%s", Head[j-1], Body[j]) > fnData;
    }
    close (fnData);
}
{ Fix( $0, FILENAME); }


